import React, { useState } from 'react';
import OptimizationActionChip from './OptimizationActionChip';
import ConfidenceScore from './ConfidenceScore';
import { formatCurrency } from '../../utils/format';
import { workflowStatusLabel } from '../../utils/actionUtils';

export default function ActionApprovalModal({
  action,
  currency = 'USD',
  isAdmin,
  onClose,
  onSubmit,
  isPending = false,
}) {
  const [note, setNote] = useState('');
  const [workflowStatus, setWorkflowStatus] = useState('approved');

  if (!action) return null;

  const savings = action.estimated_monthly_savings;

  return (
    <div className="modal-overlay" role="presentation" onClick={onClose}>
      <div
        className="modal-card action-approval-modal"
        role="dialog"
        aria-labelledby="action-approval-title"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="modal-card__header">
          <div>
            <h2 id="action-approval-title">Review action</h2>
            <p className="text-muted text-sm">{action.resource_name}</p>
          </div>
          <button type="button" className="btn-icon" onClick={onClose} aria-label="Close">×</button>
        </div>

        <div className="action-approval-modal__body">
          {/* Action details section */}
          <section className="approval-modal-section">
            <h3 className="approval-modal-section__title">Action details</h3>
            <div className="approval-modal-grid">
              <div className="approval-modal-field">
                <label className="approval-modal-label">Type</label>
                <div className="approval-modal-value">
                  <OptimizationActionChip actionType={action.action_type} />
                </div>
              </div>
              <div className="approval-modal-field">
                <label className="approval-modal-label">Confidence</label>
                <div className="approval-modal-value">
                  <ConfidenceScore confidence={action.confidence} compact />
                </div>
              </div>
              <div className="approval-modal-field">
                <label className="approval-modal-label">Current status</label>
                <div className="approval-modal-value">
                  <span className="workflow-pill">{workflowStatusLabel(action.workflow_status)}</span>
                </div>
              </div>
              {savings > 0 && (
                <div className="approval-modal-field">
                  <label className="approval-modal-label">Est. savings/mo</label>
                  <div className="approval-modal-value text-highlight">
                    {formatCurrency(savings, { currency })}
                  </div>
                </div>
              )}
            </div>
          </section>

          {/* Recommendation section */}
          {action.action_reason && (
            <section className="approval-modal-section">
              <h3 className="approval-modal-section__title">Recommendation</h3>
              <p className="approval-modal-text">{action.action_reason}</p>
            </section>
          )}

          {/* Admin controls section */}
          {isAdmin && (
            <section className="approval-modal-section">
              <h3 className="approval-modal-section__title">Approval</h3>
              <label className="form-field">
                <span className="form-label">Update status</span>
                <select
                  className="form-select"
                  value={workflowStatus}
                  onChange={(e) => setWorkflowStatus(e.target.value)}
                >
                  <option value="approved">Approved</option>
                  <option value="executed">Executed</option>
                  <option value="rejected">Rejected</option>
                  <option value="deferred">Deferred</option>
                  <option value="proposed">Proposed</option>
                </select>
              </label>
            </section>
          )}

          {/* Notes section */}
          <section className="approval-modal-section">
            <h3 className="approval-modal-section__title">Audit trail</h3>
            <label className="form-field">
              <span className="form-label">Add note (optional)</span>
              <textarea
                className="form-textarea"
                rows={3}
                value={note}
                onChange={(e) => setNote(e.target.value)}
                placeholder="Add context or reasoning for this action…"
              />
            </label>
          </section>
        </div>

        <div className="modal-card__footer">
          <button type="button" className="btn btn--ghost" onClick={onClose}>Cancel</button>
          {isAdmin && (
            <button
              type="button"
              className="btn btn--primary"
              disabled={isPending}
              onClick={() => onSubmit({ workflow_status: workflowStatus, note: note.trim() || undefined })}
            >
              {isPending ? 'Saving…' : 'Save'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
